public class ConcurrencyExceptionFilter : IExceptionFilter
{
    private readonly ILogger<ConcurrencyExceptionFilter> _logger;

    public ConcurrencyExceptionFilter(ILogger<ConcurrencyExceptionFilter> logger)
    {
        _logger = logger;
    }

    public void OnException(ExceptionContext context)
    {
        if (context.Exception is DbUpdateConcurrencyException concurrencyEx)
        {
            _logger.LogWarning(concurrencyEx, "Conflit de concurrence sur {Entity}", concurrencyEx.Entries.First().Entity.GetType().Name);

            var problemDetails = new ProblemDetails
            {
                Status = StatusCodes.Status409Conflict,
                Title = "Conflit de modification",
                Detail = "La ressource a été modifiée par un autre utilisateur. Rechargez puis réessayez.",
                Instance = context.HttpContext.Request.Path
            };

            context.Result = new ConflictObjectResult(problemDetails);
            context.ExceptionHandled = true;
        }
    }
}
```

Approche 1 : plusieurs filtres où chacun vérifie son type d’exception et pose <code>ExceptionHandled = true</code> si correspond. Ordre : NotFoundExceptionFilter, ValidationExceptionFilter, GenericExceptionFilter.<br><br>Exemple partiel :<br>```csharp
public class NotFoundExceptionFilter : IExceptionFilter
{
    public void OnException(ExceptionContext context)
    {
        if (context.Exception is NotFoundException notFound)
        {
            context.Result = new NotFoundObjectResult(new { error = notFound.Message });
            context.ExceptionHandled = true;
        }
    }
}
```
